class Solution:
    def longestPalindrome(self, s: str, t: str) -> int:
        m = [[0] * (len(t) + 1) for _ in range(len(s) + 1)]
        for i in range(len(s)):
            for j in range(len(t)):
                if s[i] == t[j]:
                    m[i + 1][j + 1] = m[i][j] + 2
                else:
                    m[i + 1][j + 1] = max(m[i + 1][j], m[i][j + 1])
        return m[-1][-1]
